CREATE TABLE IF NOT EXISTS "transaction_items" (
	"id" INTEGER NOT NULL UNIQUE GENERATED BY DEFAULT AS IDENTITY,
	"transaction_id" INTEGER,
	"product_id" INTEGER,
	"unit_price" NUMERIC,
	"quantity" NUMERIC,
	"total_line_value" NUMERIC,
	PRIMARY KEY("id")
);




CREATE TABLE IF NOT EXISTS "categories" (
	"id" INTEGER NOT NULL UNIQUE GENERATED BY DEFAULT AS IDENTITY,
	"name" VARCHAR(255),
	"created_at" NUMERIC,
	PRIMARY KEY("id")
);




CREATE TABLE IF NOT EXISTS "customer" (
	"id" INTEGER NOT NULL UNIQUE GENERATED BY DEFAULT AS IDENTITY,
	"name" VARCHAR(255),
	"email" VARCHAR(255),
	"adress" VARCHAR(255),
	"phone" NUMERIC,
	"create_at" VARCHAR(255),
	PRIMARY KEY("id")
);




CREATE TABLE IF NOT EXISTS "transaction" (
	"id" INTEGER NOT NULL UNIQUE GENERATED BY DEFAULT AS IDENTITY,
	"transaction_code" VARCHAR(255) NOT NULL,
	"customer_id" INTEGER,
	"date" DATE,
	"created_at" VARCHAR(255),
	PRIMARY KEY("id")
);




CREATE TABLE IF NOT EXISTS "products" (
	"id" INTEGER NOT NULL UNIQUE GENERATED BY DEFAULT AS IDENTITY,
	"sku" VARCHAR(255) UNIQUE,
	"name" VARCHAR(255),
	"category_id" INTEGER,
	"supplier_id" INTEGER,
	"base_price" NUMERIC,
	"created_at" NUMERIC,
	PRIMARY KEY("id")
);




CREATE TABLE IF NOT EXISTS "suppliers" (
	"id" INTEGER NOT NULL UNIQUE GENERATED BY DEFAULT AS IDENTITY,
	"name" VARCHAR(255),
	"email" VARCHAR(255),
	"created_at" NUMERIC,
	PRIMARY KEY("id")
);



ALTER TABLE "customer"
ADD FOREIGN KEY("id") REFERENCES "transaction"("customer_id")
ON UPDATE NO ACTION ON DELETE NO ACTION;
ALTER TABLE "transaction"
ADD FOREIGN KEY("id") REFERENCES "transaction_items"("transaction_id")
ON UPDATE NO ACTION ON DELETE NO ACTION;
ALTER TABLE "products"
ADD FOREIGN KEY("id") REFERENCES "transaction_items"("product_id")
ON UPDATE NO ACTION ON DELETE NO ACTION;
ALTER TABLE "products"
ADD FOREIGN KEY("category_id") REFERENCES "categories"("id")
ON UPDATE NO ACTION ON DELETE NO ACTION;
ALTER TABLE "products"
ADD FOREIGN KEY("supplier_id") REFERENCES "suppliers"("id")
ON UPDATE NO ACTION ON DELETE NO ACTION;